draw(O--A--B--C--cycle);
draw(G--D, dashed);
draw(E--F);
draw(F--G, dashed);
draw(C--F);
draw(B--E);
draw(A--D);
draw(D--E);
draw(O--G, dashed);
draw(O--X, Arrow);
draw(O--Z, Arrow);
draw(O--E, red+dashed);
draw(C--B--E--F--cycle, red);
draw(O--B, red);
draw(O--F, red+dashed);
draw(O--Y, dashed, Arrow);

label("$2$", A, S);
label("$2$", C, W);
label("$2$", G, NW);
label("$O$", O, SW);
label("$X$", X, S);
